mapper.select:
select id, config_code, config_name, logistics_id, logistics_code, logistics_name, platform_code, platform_name,
belong_owner_id, belong_owner_name, group_id, service_provider_id,
service_provider_name, state, remark, created_by, created_name, created_date, modified_by, modified_name,
modified_date, version, deleted_flag
from base_store_print_template spt
where spt.deleted_flag = 0

    and spt.group_id = #{groupId}


    and spt.service_provider_id = #{serviceProviderId}


    and spt.service_provider_id in

        #{item}



    and spt.state = #{state}


    and spt.logistics_id = #{logisticsId}


    and spt.platform_code = #{platformCode}


    and spt.platform_code in

        #{item}



    and spt.belong_owner_id = #{belongOwnerId}


    and spt.belong_owner_id in

        #{item}



    and spt.id = #{id}


    and spt.id in

        #{item}


order by spt.created_date desc

select id, config_id, logistics_id, logistics_code, logistics_name, platform_code, platform_name, 
belong_owner_id, belong_owner_name, type, template_id, template_type, template_name, external_template_name, template_url, preview_url,
brand_code, template_ext_info, auto_get_flag, service_provider_id, service_provider_name, state, remark, created_by, created_name,
created_date, modified_by, modified_name, modified_date, version, deleted_flag
from base_store_print_template_detail sptd
where sptd.deleted_flag = 0

    and sptd.service_provider_id = #{serviceProviderId}


    and sptd.config_id = #{configId}


    and sptd.state = #{state}


    and sptd.logistics_id = #{logisticsId}


    and sptd.logistics_id in

        #{item}



    and sptd.platform_code = #{platformCode}


    and sptd.template_type = #{templateType}


    and sptd.template_name like concat('%', concat(#{templateName}, '%'))


    and sptd.template_url like concat('%', concat(#{templateUrl}, '%'))

mapper.update:
update base_store_print_template_detail
config_id = #{configId}, logistics_id = #{logisticsId}, logistics_code = #{logisticsCode}, logistics_name = #{logisticsName}, platform_code = #{platformCode}, platform_name = #{platformName},
belong_owner_id = #{belongOwnerId}, belong_owner_name = #{belongOwnerName}, type = #{type}, template_id = #{templateId}, template_type = #{templateType}, template_name = #{templateName}, external_template_name = #{externalTemplateName}, template_url = #{templateUrl}, preview_url = #{previewUrl}, template_url = #{templateUrl}, brand_code = #{brandCode}, template_ext_info = #{templateExtInfo}, service_provider_id = #{serviceProviderId}, service_provider_name = #{serviceProviderName}, state = #{state}, remark = #{remark},
modified_by = #{modifiedBy}, modified_name = #{modifiedName}, modified_date = #{modifiedDate}, version = #{version}, deleted_flag = #{deletedFlag},
where id = #{id}
and version = #{version}
